<script setup>import{ref}from'vue';const p=defineProps({label:String,variant:String,size:String,disabled:Boolean,loading:Boolean,iconOnly:Boolean,type:String});const n=ref(0);function activate(e){if(p.disabled||p.loading){e.preventDefault();return}n.value++}</script><template><button :type="p.type||'button'" :class="['kumo-button',p.variant||'primary',p.size||'base']" :disabled="p.disabled||p.loading" :aria-disabled="p.disabled||undefined" :aria-busy="p.loading||undefined" :aria-label="p.iconOnly?p.label:undefined" @click="activate">{{p.loading?'Loading…':p.iconOnly?'+':p.label}}<span v-if="n" class="count"> {{n}}</span></button></template>